from flask import Flask, jsonify, request
from werkzeug.security import generate_password_hash as gpwh, check_password_hash as cph
import hashlib  # For generating a hash of the email and random token

app = Flask(__name__)

# Initialize empty lists for users' info
users = []


@app.route("/reset", methods=["POST"])
def reset():
    """
    POST request to reset user's password
    :param email: Email address of the user requesting a password reset
    :return: 200 OK when reset is successful or with an appropriate error message if there was an error
    """

    # Get the email and password from the request object.
    req = request.json
    email = req["email"]
    password = req["password"]

    # Check to see if this user exists in our list of users (which should be empty).
    existing_user = False  # By default, assume that there is no user with an e-mail address matching the one we're looking for.
    for user in users:
        print(f"Searching for {email}")

        # Check to see if this particular email matches our e-mail address of interest. If so, then we want to reset their password and return a 200 OK status code (meaning that the request was successful).
        if user["email"] == email:
            existing_user = True

            # Generate a random token for the user's email address.
            random_token = hashlib.sha512(bytes(f"{password}{email}", "utf-8")).hexdigest()

            # Store this information in our dictionary of users.
            users[users.index(user)]["randomToken"] = random_token  # Update the user's random token (in case it has been changed).
            return jsonify({"message": f"Password reset for {email} successful."}), 200

    if not existing_user:
        print(f"No user with email address {email}")

        # If we reach here, then there is no user in our list of users with an e-mail matching the one that was provided. Return a 401 status code.
        return jsonify({"message": f"No such user exists."}), 401


